-- SET clause: CURRENT_SCHEMA
ALTER SESSION SET CURRENT_SCHEMA = HR;

ALTER SESSION SET CURRENT_SCHEMA = my_schema;

ALTER SESSION SET CURRENT_SCHEMA = dba.some_schema;

-- SET clause: EDITION
ALTER SESSION SET EDITION = ora$base;

-- SET clause: ISOLATION_LEVEL
ALTER SESSION SET ISOLATION_LEVEL = SERIALIZABLE;

ALTER SESSION SET ISOLATION_LEVEL = READ COMMITTED;

-- SET clause: CONSTRAINT[S]
ALTER SESSION SET CONSTRAINT = IMMEDIATE;

ALTER SESSION SET CONSTRAINTS = DEFERRED;

ALTER SESSION SET CONSTRAINTS = DEFAULT;

-- SET clause: TIME_ZONE
ALTER SESSION SET TIME_ZONE = LOCAL;

ALTER SESSION SET TIME_ZONE = DBTIMEZONE;

ALTER SESSION SET TIME_ZONE = '+05:30';

ALTER SESSION SET TIME_ZONE = 'America/New_York';

-- SET clause: ROW ARCHIVAL VISIBILITY
ALTER SESSION SET ROW ARCHIVAL VISIBILITY = ACTIVE;

ALTER SESSION SET ROW ARCHIVAL VISIBILITY = ALL;

-- SET clause: CONTAINER (CDB / multitenant)
ALTER SESSION SET CONTAINER = CDB_ROOT;

ALTER SESSION SET CONTAINER = my_pdb SERVICE = my_service;

-- SET clause: generic NLS / init parameters
ALTER SESSION SET NLS_DATE_FORMAT = 'YYYY-MM-DD HH24:MI:SS';

ALTER SESSION SET NLS_LANGUAGE = FRENCH;

ALTER SESSION SET NLS_TERRITORY = AMERICA;

ALTER SESSION SET NLS_SORT = XSpanish;

ALTER SESSION SET NLS_DATE_LANGUAGE = German;

ALTER SESSION SET NLS_NUMERIC_CHARACTERS = '.,';

ALTER SESSION SET NLS_ISO_CURRENCY = America;

ALTER SESSION SET NLS_CURRENCY = 'DM';

ALTER SESSION SET QUERY_REWRITE_ENABLED = TRUE;

ALTER SESSION SET QUERY_REWRITE_INTEGRITY = TRUSTED;

ALTER SESSION SET OPTIMIZER_MODE = ALL_ROWS;

ALTER SESSION SET SQL_TRACE = TRUE;

ALTER SESSION SET TRACEFILE_IDENTIFIER = 'my_trace';

ALTER SESSION SET STANDBY_MAX_DATA_DELAY = NONE;

ALTER SESSION SET STANDBY_MAX_DATA_DELAY = 30;

-- SET clause: reset a parameter to its instance default (DEFAULT is reserved)
ALTER SESSION SET NLS_DATE_FORMAT = DEFAULT;

ALTER SESSION SET OPTIMIZER_MODE = DEFAULT;

-- SET clause: reset a parameter to its instance default
ALTER SESSION SET NLS_DATE_FORMAT = DEFAULT;

ALTER SESSION SET OPTIMIZER_MODE = DEFAULT;

-- SET clause: multi-token / expression values
ALTER SESSION SET RESULT_CACHE_REMOTE_EXPIRATION = 60 * 5;

ALTER SESSION SET DEFAULT_SDO_RESOLUTION = ROUND(1.5 + 0.5);

ALTER SESSION SET COMMIT_WRITE = 'BATCH,NOWAIT';

-- SET parameter whose name starts with a promoted unreserved keyword (DML)
ALTER SESSION SET DML_LOCKS = 0;

-- SET parameter whose name starts with a promoted unreserved keyword (PARALLEL)
ALTER SESSION SET PARALLEL_DEGREE_POLICY = AUTO;

-- Multiple SET parameters in one statement
ALTER SESSION SET NLS_LANGUAGE = ENGLISH NLS_TERRITORY = AMERICA;

ALTER SESSION SET NLS_DATE_FORMAT = 'DD-MON-YYYY' NLS_NUMERIC_CHARACTERS = ',.';

-- Mix of specifically-handled and generic SET parameters in one statement
ALTER SESSION SET ISOLATION_LEVEL = SERIALIZABLE NLS_LANGUAGE = ENGLISH;

ALTER SESSION SET CONSTRAINTS = IMMEDIATE NLS_DATE_FORMAT = 'YYYY-MM-DD';

ALTER SESSION SET TIME_ZONE = 'UTC' NLS_SORT = BINARY ISOLATION_LEVEL = READ COMMITTED;

-- ADVISE clause
ALTER SESSION ADVISE COMMIT;

ALTER SESSION ADVISE ROLLBACK;

ALTER SESSION ADVISE NOTHING;

-- CLOSE DATABASE LINK
ALTER SESSION CLOSE DATABASE LINK remote_db;

ALTER SESSION CLOSE DATABASE LINK hr_link;

-- ENABLE / DISABLE COMMIT IN PROCEDURE
ALTER SESSION ENABLE COMMIT IN PROCEDURE;

ALTER SESSION DISABLE COMMIT IN PROCEDURE;

-- ENABLE / DISABLE GUARD
ALTER SESSION ENABLE GUARD;

ALTER SESSION DISABLE GUARD;

-- ENABLE / DISABLE PARALLEL
ALTER SESSION ENABLE PARALLEL DML;

ALTER SESSION ENABLE PARALLEL DDL;

ALTER SESSION ENABLE PARALLEL QUERY;

ALTER SESSION DISABLE PARALLEL DML;

ALTER SESSION DISABLE PARALLEL DDL;

ALTER SESSION DISABLE PARALLEL QUERY;

-- ENABLE PARALLEL with degree-of-parallelism
ALTER SESSION ENABLE PARALLEL DML PARALLEL 4;
ALTER SESSION ENABLE PARALLEL DDL PARALLEL 8;
ALTER SESSION ENABLE PARALLEL QUERY PARALLEL 2;

-- FORCE PARALLEL
ALTER SESSION FORCE PARALLEL DML;

ALTER SESSION FORCE PARALLEL DDL;

ALTER SESSION FORCE PARALLEL QUERY;

ALTER SESSION FORCE PARALLEL DML PARALLEL 4;

ALTER SESSION FORCE PARALLEL DDL PARALLEL 8;

ALTER SESSION FORCE PARALLEL QUERY PARALLEL 2;

-- RESUMABLE
ALTER SESSION ENABLE RESUMABLE;

ALTER SESSION ENABLE RESUMABLE TIMEOUT 3600;

ALTER SESSION ENABLE RESUMABLE NAME 'my_resumable_session';

ALTER SESSION ENABLE RESUMABLE TIMEOUT 7200 NAME 'long_running_job';

ALTER SESSION DISABLE RESUMABLE;

-- SHARD DDL
ALTER SESSION ENABLE SHARD DDL;

ALTER SESSION DISABLE SHARD DDL;

-- SYNC WITH PRIMARY
ALTER SESSION SYNC WITH PRIMARY;
